class Solution:
    def maximalRectangle(self, matrix):
        if not matrix or not matrix[0]:
            return 0
        rows = len(matrix)
        cols = len(matrix[0])
        best = 0
        for top in range(rows):
            for left in range(cols):
                if matrix[top][left] != '1':
                    continue
                max_right = cols
                for bottom in range(top, rows):
                    right = left
                    while right < max_right and matrix[bottom][right] == '1':
                        right += 1
                    max_right = min(max_right, right)
                    if max_right <= left:
                        break
                    best = max(best, (bottom - top + 1) * (max_right - left))
        return best

